import { Meta } from "@storybook/addon-docs/blocks";
import * as Story from "./use-click-outside.stories";

<Meta of={Story} title="Hooks/useClickOutside" />

# useClickOutside

The `useClickOutside` hook listens for click events outside a specified element and calls a handler function when such an event occurs.

### Usage

```tsx
import React, { useRef, useState } from "react";
import { useClickOutside } from "chop-logic-components";

const ExampleComponent = () => {
  const [isOpen, setIsOpen] = useState(false);
  const ref = useRef(null);

  useClickOutside({
    ref,
    onClickOutsideHandler: () => setIsOpen(false),
  });

  return (
    <div>
      <button onClick={() => setIsOpen(true)}>Open</button>
      {isOpen && <div ref={ref}>Click outside me to close</div>}
    </div>
  );
};

export default ExampleComponent;
```

### Parameters

| Param                     | Type                           | Description                                                                                        |
| ------------------------- | ------------------------------ | -------------------------------------------------------------------------------------------------- |
| **ref**                   | `React.RefObject<HTMLElement>` | A ref to the element that will be used to check if the click event is within the element's bounds. |
| **onClickOutsideHandler** | `() => void`                   | The callback function to call when a click outside the referenced element is detected.             |
| **dependentRef**          | `React.RefObject<HTMLElement>` | An optional additional ref to another element that should not trigger the outside click handler.   |

### Returns

`void`

